// nodes/filterNode.js
import { BaseNode } from './BaseNode';
import { Filter } from 'lucide-react';

export const FilterNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="Filter"
      icon={Filter}
      accentColor="var(--accent-rose)"
      inputs={[{ id: 'input', label: 'input' }]}
      outputs={[
        { id: 'true', label: 'true' },
        { id: 'false', label: 'false' },
      ]}
      selected={selected}
    >
      <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
        <div style={{ fontSize: '11px', color: 'var(--text-tertiary)', marginBottom: 4 }}>Condition:</div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
          <span style={{ fontWeight: 600, color: 'var(--accent-rose)', fontSize: '11px', padding: '2px 4px', background: 'rgba(244, 63, 94, 0.1)', borderRadius: '4px' }}>
            {data?.operator || 'contains'}
          </span>
          <span style={{ fontWeight: 500, color: 'var(--text-primary)' }}>
            "{data?.condition || '...'}"
          </span>
        </div>
      </div>
    </BaseNode>
  );
};
